class Parser {
public:
    // Use a smart pointer to manage lifetime automatically
    std::shared_ptr<ParseNode> parse(const std::string& input);
    // ... other members
private:
    // Cache keyed by input location; ensures no stale pointers remain
    std::unordered_map<std::size_t, std::shared_ptr<ParseNode>> cache;
